  "code": "const sleep = function (ms) {
  return new Promise(function (resolve) { setTimeout(resolve, ms); });
};
const normalizeName = function (name) {
  return (name || '').toLowerCase().replace(/^minecraft:/, '').replace(/_/g, ' ');
};
const findWeapon = function () {
  const goal = normalizeName(args.weapon);
  return bot.inventory.items().find(function (item) {
    return normalizeName(item.name).includes(goal) || normalizeName(item.displayName).includes(goal);
  });
};
if (bot.health <= 0) {
  return "<FAILED>: The bot is currently dead and cannot attack.";
}
const initialWeapon = findWeapon();
if (!initialWeapon) {
  return "<NO_WEAPON>: Could not find " + args.weapon + " in inventory.";
}
startBackgroundSkill(bot, 'melee_attack_nearest_hostile', async function (token) {
  while (!token.cancelled && bot.health > 0 && Boolean(bot.entity)) {
    if (!bot.physicsEnabled) {
      await sleep(100);
      continue;
    }
    const weapon = findWeapon();
    if (weapon) {
      if (!bot.heldItem || bot.heldItem.name !== weapon.name) {
        try {
          await bot.equip(weapon, 'hand');
        } catch (e) {}
      }
    }
    let target = null;
    if (args.target_id !== undefined) {
      target = bot.entities[args.target_id];
    }
    if (!target || target.health <= 0 || !target.isValid) {
      target = bot.nearestEntity(function (e) {
        if (e.type !== 'mob' && e.type !== 'hostile') return false;
        const dist = e.position.distanceTo(bot.entity.position);
        const hostileNames = ['zombie', 'skeleton', 'creeper', 'spider', 'enderman', 'witch', 'drowned', 'husk', 'stray'];
        return dist < 8 && hostileNames.includes(e.name);
      });
    }
    if (target) {
      const distance = bot.entity.position.distanceTo(target.position);
      if (distance < 4.5) {
        await bot.lookAt(target.position.offset(0, (target.height || 1) * 0.8, 0));
        bot.attack(target);
      }
    } else if (args.target_id !== undefined) {
      break;
    }
    await sleep(650);
  }
});
return "<ATTACKING>: Started melee attack routine with " + args.weapon + ".";"
}
